@component(base_image='python:3.10-slim')
def evaluate_model(
    model_dir: Input[Model],
    metrics_out: Output[Metrics],
    threshold: float = 0.92,
) -> NamedTuple('Outputs', [('approved', bool)]):
    import json, pathlib
    results = json.loads((pathlib.Path(model_dir.path) / 'eval.json').read_text())
    approved = results['accuracy'] >= threshold
    metrics_out.log_metric('accuracy', results['accuracy'])
    metrics_out.log_metric('approved', int(approved))
    return (approved,)
